import { trottle } from "~/utils/tools";
export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
       link: [{ rel: "icon", type: "image/x-icon", href: this.$store.getters.favicon}],
    };
  },
  components: {},
  watchQuery: true,
  async asyncData({ $get, params, query }) {
    const { type } = params;
    const { name } = query;
    const data = { page_size: 20, type, name, type };
    if (type == 1) {
      (data.sort = "desc"), (data.sort_type = "sales_sum");
    }
    const {
      data: { list, count },
    } = await $get("pc/goodsList", { params: data });
    const { data: indexData } = await $get("pc/index");
    let ad = {};
    switch (type) {
      case "1":
        ad = indexData.host_ad;
        break;
      case "2":
        ad = indexData.new_ad;
        break;
      case "3":
        ad = indexData.best_ad;
        break;
    }
    return { goodsList: list, count, ad };
  },
  data() {
    return {
      sortType: "",
      saleSort: "desc",
      priceSort: "desc",
      page: "",
    };
  },
  created() {
    this.changeSortType = trottle(this.changeSortType, 500, this);
  },
  methods: {
    changeSortType(type) {
      this.sortType = type;
      switch (type) {
        case "price":
          if (this.priceSort == "asc") {
            this.priceSort = "desc";
          } else if (this.priceSort == "desc") {
            this.priceSort = "asc";
          }
          break;
        case "sales_sum":
          if (this.saleSort == "asc") {
            this.saleSort = "desc";
          } else if (this.saleSort == "desc") {
            this.saleSort = "asc";
          }
          break;
        default:
      }
      this.getGoods();
    },
    changePage(current) {
      this.page = current;
      this.getGoods();
    },
    async getGoods() {
      const { name } = this.$route.query;
      const { priceSort, sortType, saleSort } = this;
      let sort = "";
      switch (sortType) {
        case "price":
          sort = priceSort;
          break;
        case "sales_sum":
          sort = saleSort;
          break;
      }
      const {
        data: { list, count },
      } = await this.$get("pc/goodsList", {
        params: {
          page_size: 20,
          page_no: this.page,
          sort_type: sortType,
          sort,
          name,
        },
      });
      this.goodsList = list;
    },
  },
};
